const items=$input.all();const picks=items[0]?.json||[];const alerts=items[1]?.json||[];const mkt=items[2]?.json||{};const today=new Date().toISOString().split('T')[0];const pl=Array.isArray(picks)?picks:[picks];const al=Array.isArray(alerts)?alerts:[alerts];
let h=`<html><head><style>body{font-family:Arial;max-width:900px;margin:0 auto;padding:20px}table{border-collapse:collapse;width:100%}th,td{border:1px solid #ddd;padding:8px;text-align:left}th{background:#2c3e50;color:white}.hi{color:#27ae60;font-weight:bold}.wr{background:#fff3cd}</style></head><body><h1>Stock Report - ${today}</h1><h2>Market Outlook</h2><p>${mkt.summary||'No analysis available.'}</p><h2>Top Picks</h2><table><tr><th>Ticker</th><th>Strategy</th><th>Score</th><th>Fund</th><th>Tech</th><th>Sent</th><th>Rec</th></tr>`;
for(const p of pl){if(!p.ticker)continue;h+=`<tr><td><b>${p.ticker}</b></td><td>${p.strategy}</td><td class='${p.overall_score>=7?"hi":""}'>${p.overall_score}</td><td>${p.fundamental_score}</td><td>${p.technical_score}</td><td>${p.sentiment_score}</td><td>${p.recommendation}</td></tr>`;}
h+=`</table><h2>Alerts</h2><table><tr><th>Ticker</th><th>Type</th><th>Message</th><th>Severity</th></tr>`;for(const a of al){if(!a.ticker)continue;h+=`<tr class='${a.severity==="warning"?"wr":""}'><td>${a.ticker}</td><td>${a.alert_type}</td><td>${a.message}</td><td>${a.severity}</td></tr>`;}
h+=`</table></body></html>`;return [{json:{report_date:today,html_report:h,picks_count:pl.length,alerts_count:al.length}}];
